# ==== SECURITY AUDIT ====
PROJECTS['security-audit'] = {
    'name': 'security-audit',
    'description': 'Multi-tool security audit: port scan + password + SSL check',
    'files': {
        'security_audit.py': 'import socket, concurrent.futures, hashlib, re\n\nCOMMON_PORTS = [21, 22, 23, 25, 53, 80, 110, 143, 443, 445, 3306, 3389, 5432, 6379, 8080, 8443, 27017]\nSERVICES = {21:"FTP",22:"SSH",23:"Telnet",25:"SMTP",53:"DNS",80:"HTTP",443:"HTTPS",445:"SMB",3306:"MySQL",3389:"RDP",5432:"PostgreSQL",6379:"Redis",8080:"Proxy",27017:"MongoDB"}\n\ndef port_scan(host, ports=None):\n    if ports is None: ports = COMMON_PORTS\n    results = []\n    def check(p):\n        try:\n            with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s:\n                s.settimeout(1)\n                if s.connect_ex((host, p)) == 0:\n                    return (p, SERVICES.get(p, "Unknown"), "open")\n        except: pass\n        return None\n    with concurrent.futures.ThreadPoolExecutor(20) as ex:\n        for f in concurrent.futures.as_completed({ex.submit(check, p): p for p in ports}):\n            r = f.result()\n            if r: results.append(r)\n    return sorted(results)\n\ndef password_strength(pwd):\n    score = 0\n    issues = []\n    if len(pwd) >= 8: score += 20\n    else: issues.append("Too short")\n    if len(pwd) >= 12: score += 15\n    if re.search(r"[a-z]", pwd): score += 10\n    else: issues.append("Missing lowercase")\n    if re.search(r"[A-Z]", pwd): score += 10\n    else: issues.append("Missing uppercase")\n    if re.search(r"\\d", pwd): score += 10\n    else: issues.append("Missing numbers")\n    if re.search(r"[^a-zA-Z0-9]", pwd): score += 20\n    else: issues.append("Missing special chars")\n    if pwd.lower() in ["password","123456","admin","letmein","qwerty","welcome"]: score -= 50; issues.append("Common password")\n    level = "Strong" if score >= 70 else "Moderate" if score >= 40 else "Weak"\n    return {"score": max(0, min(100, score)), "level": level, "issues": issues}\n\ndef ssl_check(host, port=443):\n    try:\n        import ssl\n        ctx = ssl.create_default_context()\n        with socket.create_connection((host, port), timeout=5) as sock:\n            with ctx.wrap_socket(sock, server_hostname=host) as ssock:\n                cert = ssock.getpeercert()\n                return {"host": host, "valid": True, "expires": cert.get("notAfter"), "tls": ssock.version()}\n    except Exception as e:\n        return {"host": host, "valid": False, "error": str(e)}\n\ndef audit(host):\n    print(f"=== Security Audit: {host} ===\\n")\n    ports = port_scan(host)\n    if ports:\n        print(f"Open ports ({len(ports)}):")\n        for p, svc, st in ports:\n            risk = "HIGH" if p in [21,23,445,3389] else "MED" if p in [22,25,3306] else "LOW"\n            print(f"  {p:5d} {svc:12s} [{risk}]")\n    print()\n    print("Password demo:")\n    for p in ["hello123", "P@ssw0rd!", "SuperStr0ng!Pass"]:\n        r = password_strength(p)\n        print(f"  {p:20s} -> {r[\'level\']:8s} ({r[\'score\']})")\n\nif __name__ == "__main__":\n    import sys\n    audit(sys.argv[1] if len(sys.argv) > 1 else "localhost")',
        'README.md': '# Security Audit Toolkit\n\nPort scanner, password strength analyzer, SSL checker.\n\n## Run\n```\npython security_audit.py [hostname]\n```'
    }
}

# ==== HYBRID SEARCH ====
PROJECTS['hybrid-search'] = {
    'name': 'hybrid-search',
    'description': 'Hybrid keyword + semantic search engine',
    'files': {
        'hybrid_search.py': 'import numpy as np\n\nclass HybridSearch:\n    """Combines keyword relevance with semantic similarity."""\n    def __init__(self):\n        self.docs = []\n        self.embeddings = []\n        self.index = {}\n\n    def add(self, doc_id, text, embedding):\n        self.docs.append({"id": doc_id, "text": text})\n        self.embeddings.append(embedding)\n        for word in set(text.lower().split()):\n            if word not in self.index:\n                self.index[word] = []\n            self.index[word].append(len(self.docs) - 1)\n\n    def search(self, query, query_embedding, alpha=0.5, k=5):\n        words = set(query.lower().split())\n        kw_scores = {}\n        for word in words:\n            for idx in self.index.get(word, []):\n                kw_scores[idx] = kw_scores.get(idx, 0) + 1\n        max_kw = max(kw_scores.values()) if kw_scores else 1\n\n        if not self.embeddings: return []\n        emb_matrix = np.stack(self.embeddings)\n        sem_scores = query_embedding @ emb_matrix.T\n\n        scored = []\n        for i in range(len(self.docs)):\n            kw_norm = kw_scores.get(i, 0) / max_kw\n            sem_norm = float(sem_scores[0, i])\n            combined = alpha * kw_norm + (1 - alpha) * sem_norm\n            scored.append((combined, self.docs[i]))\n\n        scored.sort(reverse=True)\n        return [doc for _, doc in scored[:k]]\n\n# Demo\nif __name__ == "__main__":\n    hs = HybridSearch()\n    hs.add(1, "Python is a programming language", np.random.randn(384))\n    hs.add(2, "Flask is a web framework for Python", np.random.randn(384))\n    hs.add(3, "Machine learning with neural networks", np.random.randn(384))\n    results = hs.search("python web", np.random.randn(384))\n    print(f"Found {len(results)} results")',
        'README.md': '# Hybrid Search Engine\n\nKeyword + semantic hybrid search.\n\n## Usage\n```python\nfrom hybrid_search import HybridSearch\nhs = HybridSearch()\nhs.add(1, "text", embedding)\nresults = hs.search("query", query_emb)\n```'
    }
}

# ==== NANOBOT API FRAMEWORK ====
PROJECTS['nanobot-api'] = {
    'name': 'nanobot-api',
    'description': 'Novel API framework inspired by nanobot swarm architecture',
    'files': {
        'nanobot_api.py': '"""Nanobot API Framework\n\nEach endpoint is a "nanobot" with confidence scoring and health stats.\n"""\nfrom http.server import HTTPServer, BaseHTTPRequestHandler\nimport json, time\n\nclass Nanobot:\n    def __init__(self, name, handler):\n        self.name = name\n        self.handler = handler\n        self.calls = 0\n        self.errors = 0\n        self.total_time = 0\n        self.confidence = 1.0\n\n    def __call__(self, *args):\n        self.calls += 1\n        t0 = time.time()\n        try:\n            result = self.handler(*args)\n            self.total_time += time.time() - t0\n            return result\n        except Exception as e:\n            self.errors += 1\n            self.confidence *= 0.9\n            raise\n\n    @property\n    def avg_time(self):\n        return (self.total_time / self.calls) if self.calls else 0\n\nclass SwarmAPI:\n    def __init__(self, name="Keli API"):\n        self.name = name\n        self.bots = []\n        self.start = time.time()\n\n    def endpoint(self, method="GET"):\n        def dec(fn):\n            bot = Nanobot(fn.__name__, fn)\n            bot.method = method\n            bot.path = "/" + fn.__name__ if fn.__name__ != "root" else "/"\n            self.bots.append(bot)\n            return bot\n        return dec\n\n    def find(self, path, method):\n        for b in self.bots:\n            if getattr(b, "path", None) == path and getattr(b, "method", "GET") == method:\n                return b\n        return None\n\n    def health(self):\n        avg_conf = sum(b.confidence for b in self.bots) / max(len(self.bots), 1)\n        return {\n            "name": self.name,\n            "uptime": round(time.time() - self.start, 1),\n            "bots": len(self.bots),\n            "total_calls": sum(b.calls for b in self.bots),\n            "total_errors": sum(b.errors for b in self.bots),\n            "confidence": round(avg_conf, 4),\n            "status": "healthy" if avg_conf > 0.5 else "degraded",\n            "details": [{"name": b.name, "calls": b.calls, "errors": b.errors,\n                        "avg_ms": round(b.avg_time * 1000, 1), "confidence": round(b.confidence, 3)}\n                       for b in self.bots]\n        }\n\n# Create API\napi = SwarmAPI()\n\n@api.endpoint("GET")\ndef root():\n    return {"service": api.name, "status": "online"}\n\n@api.endpoint("GET")\ndef health():\n    return api.health()\n\n@api.endpoint("POST")\ndef echo(data):\n    return {"you_sent": data, "ts": time.time()}\n\nclass Handler(BaseHTTPRequestHandler):\n    def do_GET(self):\n        bot = api.find(self.path, "GET")\n        if not bot: self.send_error(404); return\n        try:\n            res = bot()\n            self.send_json(200, res)\n        except Exception as e:\n            self.send_json(500, {"error": str(e)})\n\n    def do_POST(self):\n        bot = api.find(self.path, "POST")\n        if not bot: self.send_error(404); return\n        length = int(self.headers.get("Content-Length", 0))\n        body = json.loads(self.rfile.read(length)) if length else {}\n        try:\n            res = bot(body)\n            self.send_json(200, res)\n        except Exception as e:\n            self.send_json(500, {"error": str(e)})\n\n    def send_json(self, code, data):\n        self.send_response(code)\n        self.send_header("Content-Type", "application/json")\n        self.end_headers()\n        self.wfile.write(json.dumps(data).encode())\n\nif __name__ == "__main__":\n    server = HTTPServer(("0.0.0.0", 8080), Handler)\n    print(f\"{api.name} running on :8080\")\n    print(json.dumps(api.health(), indent=2))\n    server.serve_forever()\n\n# Example client\n# import requests; print(requests.get(\"http://localhost:8080/\").json())',
        'client.py': 'import requests\nBASE = "http://localhost:8080"\nprint("Root:", requests.get(BASE + "/").json())\nprint("Health:", requests.get(BASE + "/health").json())\nprint("Echo:", requests.post(BASE + "/echo", json={"hello": "world"}).json())',
        'README.md': '# Nanobot API Framework\n\nNovel API framework where each endpoint is a nanobot with confidence scoring.\n\n## Run\n```\npython nanobot_api.py\n# In another terminal: python client.py\n```'
    }
}

