PROJECTS['event-mesh'] = {
    'name': 'event-mesh',
    'description': 'Event-driven microservice mesh with async routing',
    'files': {
        'event_mesh.py': '"""Event Mesh — async event-driven microservice architecture."""\nimport asyncio\n\nclass EventBus:\n    def __init__(self):\n        self.subscribers = {}\n        self.history = []\n\n    def subscribe(self, event_type):\n        def dec(handler):\n            self.subscribers.setdefault(event_type, []).append(handler)\n            return handler\n        return dec\n\n    async def publish(self, event_type, data=None):\n        entry = {"type": event_type, "data": data or {}}\n        self.history.append(entry)\n        for handler in self.subscribers.get(event_type, []):\n            result = handler(entry)\n            if asyncio.iscoroutine(result):\n                await result\n\nclass Service:\n    def __init__(self, name, bus):\n        self.name = name\n        self.bus = bus\n\n    async def emit(self, event_type, data=None):\n        print(f"  [{self.name}] -> {event_type}")\n        await self.bus.publish(event_type, data)\n\nasync def demo():\n    bus = EventBus()\n\n    @bus.subscribe("user.created")\n    def handle_user(event):\n        print(f"  [Users] Creating: {event[\'data\']}")\n\n    @bus.subscribe("order.placed")\n    async def handle_order(event):\n        print(f"  [Orders] Processing order: {event[\'data\']}")\n        await bus.publish("notification.send", {"type": "order_confirm", "user": event[\'data\'][\'user\"]})\n\n    @bus.subscribe("notification.send")\n    def handle_notif(event):\n        print(f"  [Notifications] Sending to {event[\'data\'][\'user\"]}")\n\n    await bus.publish("user.created", {"email": "alice@test.com", "name": "Alice"})\n    await bus.publish("order.placed", {"order_id": "ORD-001", "user": "alice@test.com", "total": 49.99})\n\n    print(f"\\nTotal events: {len(bus.history)}")\n\nif __name__ == "__main__":\n    asyncio.run(demo())',
        'README.md': '# Event Mesh\n\nAsync event-driven microservice pattern.\n\n## Run\n```\npython event_mesh.py\n```'
    }
}

